use std::io::{self, Read};
fn min_window(s: &str, t: &str) -> String { let mut need = [0i32; 128]; let mut missing = t.len() as i32; for &b in t.as_bytes() { need[b as usize] += 1; } let bytes = s.as_bytes(); let mut left = 0usize; let mut best_start = 0usize; let mut best_len = s.len() + 1; for right in 0..bytes.len() { let c = bytes[right] as usize; if need[c] > 0 { missing -= 1; } need[c] -= 1; while missing == 0 { if right - left + 1 < best_len { best_start = left; best_len = right - left + 1; } let lc = bytes[left] as usize; need[lc] += 1; if need[lc] > 0 { missing += 1; } left += 1; } } if best_len > s.len() { String::new() } else { s[best_start..best_start + best_len].to_string() } }
fn main() { let mut input=String::new(); io::stdin().read_to_string(&mut input).unwrap(); let lines: Vec<&str>=input.lines().collect(); if !lines.is_empty(){ let t:usize=lines[0].parse().unwrap(); let mut out=Vec::new(); for i in 0..t { out.push(min_window(lines[1+2*i], lines[2+2*i])); } print!("{}", out.join("\n")); } }
